const ContenedorLateral = ({ subtitulo, texto, imagen }) => {
  return (
    <div className="relative w-[30vw] h-[60vh] bg-black rounded-tl-2xl p-6 flex flex-col items-center justify-start z-10 shadow-2xl ml-auto">
      {/* Subtítulo en óvalo blanco */}
      <div className="absolute -top-5 bg-white rounded-full px-6 py-2 text-sm font-semibold shadow text-black">
        {subtitulo}
      </div>

      {/* Contenido dentro del contenedor */}
      <div className="mt-8 w-full text-white text-sm text-center space-y-6">
        <p className="leading-relaxed">{texto}</p>

        <div className="flex justify-center">
          <img
            src={imagen}
            alt="contenido dinámico"
            className="rounded-lg object-contain max-w-[90%] max-h-[30vh]"
          />
        </div>
      </div>
    </div>
  );
};
